+
+/// Generate bisect.bisect(a, x, lo=0, hi=len(a)) -> index (alias for bisect_right)
+pub fn genBisect(self: *NativeCodegen, args: []ast.Node) CodegenError!void {
+    try genBisectRight(self, args);
+}
