+    try self.emitIndent();
+    try self.emit("const _result = _heap.items[0];\n");
+    try self.emitIndent();
+    try self.emit("_heap.items[0] = _item;\n");
+    try self.emitIndent();
+    try self.emit("break :heapq_pushpop_blk _result;\n");
+    self.dedent();
+    try self.emitIndent();
+    try self.emit("}");
+}
